#include<bits/stdc++.h>
using namespace std;
int a[3030][3030],b[3030][3030],c[3030][3030];
long long e[3030],f[3030],g[3030];
const long long mod=998244353;
int main()
{
    int t;
    scanf("%d",&t);
    while(t--)
    {
        int n;
        scanf("%d",&n);
        for(int i=1;i<=n;i++)
        {
            for(int j=1;j<=n;j++)
            {
                scanf("%d",&a[i][j]);
            }
        }
        for(int i=1;i<=n;i++)
        {
            for(int j=1;j<=n;j++)
            {
                scanf("%d",&b[i][j]);
            }
        }
        for(int i=1;i<=n;i++)
        {
            for(int j=1;j<=n;j++)
            {
                scanf("%d",&c[i][j]);
            }
        }
        memset(e,0,sizeof(e));
        memset(f,0,sizeof(f));
        memset(g,0,sizeof(g));
        for(int i=1;i<=n;i++)
        {
            for(int j=1;j<=n;j++)
            {
                e[i]=(e[i]+1ll*a[j][i])%mod;
                g[i]=(g[i]+1ll*c[j][i])%mod;
            }
        }
        for(int i=1;i<=n;i++)
        {
            for(int j=1;j<=n;j++)
            {
                f[i]=(f[i]+1ll*e[j]*b[j][i]%mod)%mod;
            }
        }
        int flag=1;
        for(int i=1;i<=n;i++)
        {
            if(f[i]!=g[i])
            {
                flag=0;
                break;
            }
        }
        if(flag)
        {
            printf("Yes\n");
        }
        else
        {
            printf("No\n");
        }
    }
    return 0;
}
